-- Enrichment marathon batch: Open eClass, Open Food Network, Open HRMS, Open Policy Agent, Open QuarterMaster, Open Source Routing Machine (OSRM), Open Web Analytics, Open WebUI

-- ── Open eClass ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open eClass is a free, open-source Course Management System built by the Greek Academic Network (GUnet) that lets universities, schools, and training organizations run asynchronous e-learning, host course materials, and manage online classrooms.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$Nonprofit academic consortium (GUnet); staff count not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Athens, Greece$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Greek$q$, $q$and dozens of community-translated interface languages$q$]::text[],
  seo_title = COALESCE($q$Open eClass Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Open eClass review: the free, open-source course management system from GUnet used by universities. Features, hosting options, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Open eClass (formerly GUnet eClass) is a free, open-source Course Management System (CMS) originally released on 13 February 2003 by the Asynchronous Teleducation (Teledu) team of the Greek Academic Network (GUnet), a consortium of Greek academic and research institutions founded in 2000 and based in Athens. The first version was built on top of the open-source Claroline platform, and over more than two decades the project has gone through four major generations (1.x through 4.x), with 43+ major releases and 136+ sub-versions distributed under the GNU GPL license. Open eClass is designed to remove the geographic and scheduling barriers of traditional classroom teaching by giving instructors tools to publish course materials, manage enrollment and access control, host assignments and assessments, run discussion forums and messaging, and track student activity, all without requiring proprietary software or per-seat licensing fees. It emphasizes cross-platform compatibility, open standards, and interoperability with other university IT systems, and supports a multilingual interface (Greek and English primary, with community translations into many other languages), making it usable well beyond Greece. There are two main ways to run it: self-hosting the open-source codebase on institutional servers for full control, or using GUnet's free hosted service at free.openeclass.org, aimed at smaller institutions that lack the IT resources to maintain their own installation. Because it is free and non-commercial, Open eClass competes primarily with other open-source learning management systems such as Moodle, Sakai, and Claroline (its original ancestor) rather than commercial platforms like Canvas or Blackboard. Its core differentiators are its two-decade track record inside the Greek higher-education system (used by the large majority of Greek universities and many K-12 schools), its zero-licensing-cost model, and its GUnet-backed long-term maintenance, which is unusual for a community open-source LMS. Target users are universities, colleges, vocational training centers, and school networks, especially those in the public sector or with limited software budgets, that want a mature, stable LMS without vendor lock-in. Because it is not a venture-backed startup product, there is no funding history, subscription tiers, or enterprise sales motion; adoption spreads through direct institutional deployment and GUnet's academic network rather than commercial marketing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '128ae277-f9ab-42e4-8593-e90d754504e5';

