-- ── Open Food Network ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open Food Network is a nonprofit, open-source online marketplace platform that connects food producers directly with shoppers, food hubs, and buying groups, enabling short, transparent local food supply chains in 20+ countries.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (fees apply above a monthly sales threshold in most regions)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Distributed nonprofit network with country-level teams; global staff count not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Melbourne, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Spanish$q$, $q$Portuguese$q$, $q$and additional locale translations by country instance$q$]::text[],
  seo_title = COALESCE($q$Open Food Network Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Open Food Network review: the open-source marketplace platform for local food systems. Features for producers and hubs, pricing by region, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Open Food Network (OFN) is an open-source, not-for-profit online marketplace platform founded in 2012 in Melbourne, Australia, by Kirsten Larsen and Serenity Hill. It was created to help rebuild local, transparent food supply chains by giving farmers, food hubs, buying groups, and farmers' markets an e-commerce platform to sell directly to consumers without relying on conventional retail intermediaries. The platform is stewarded globally by the Open Food Foundation, a registered nonprofit charity established in October 2012 to develop and protect the open-source code, applications, and knowledge behind the network as a shared commons rather than proprietary software owned by a single company. Since its Australian launch, Open Food Network has spread to more than 20 countries, each typically run by a locally-led affiliate organization (for example Open Food Network UK, Open Food Network Canada, Open Food France) that adapts governance, support, and pricing to local needs while sharing the same underlying open-source codebase hosted on GitHub. Functionally, the platform lets individual producers create independent online stores, lets food hubs and buying groups aggregate products from multiple producers into a single storefront, and supports pre-ordering for farmers' markets and community-supported agriculture (CSA) style buying groups. Because it is community-governed, Open Food Network does not take a percentage of sales the way commercial marketplaces like Shopify or Faire do; instead it operates on a threshold-based fee model that varies by country instance. In Australia and the UK, for example, shops can trade for free as long as monthly turnover stays under roughly AUD 500 or GBP 500, after which the platform typically charges a small percentage (around 2-3%) of the amount over that threshold, while a shop's own admin/hub fee (often 15-30%, set by the shop, not by OFN) is separate and goes to the hub operator rather than the platform. The core software itself remains free and open source for anyone to self-host. OFN's main differentiators are its explicit nonprofit, commons-based governance (no venture capital, no lock-in, no data resale), its purpose-built support for multi-producer food hub aggregation rather than generic e-commerce, and its global community of country-level affiliates who provide local training and support. Competitors include general e-commerce platforms adapted for food (Shopify, WooCommerce), CSA-specific tools like Farmigo and Local Line, and other food-hub software, but none combine OFN's open-source, nonprofit, internationally federated model. Target users are small-to-mid-size farmers, food hubs, buying groups, farmers' markets, and community food organizations focused on short supply chains and food system transparency rather than maximum transaction volume.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a8beb2a4-e936-455d-aa4d-c21b017173fb';

