-- ── Open HRMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open HRMS is an open-source human resource management system built on the Odoo framework by Cybrosys Technologies, covering recruitment, attendance, payroll, and appraisal for small and large organizations.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (core modules); paid support plans from $49.90/month$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$51-200 employees (Cybrosys Technologies)$q$, company_size),
  headquarters = COALESCE($q$Kozhikode, Kerala, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Open HRMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Open HRMS review: the open-source, Odoo-based HR management system from Cybrosys. Features, pricing plans from $49.90/month, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Open HRMS is an open-source human resource management system built as a module suite on top of Odoo, the open-source ERP framework, and developed and maintained by Cybrosys Technologies, an Odoo Gold Partner founded in 2008 and headquartered in Kozhikode, Kerala, India. The Open HRMS project itself was introduced as a dedicated, community-facing HR distribution of Odoo's HR apps, packaging onboarding, attendance, leave management, appraisal, payroll, recruitment, and employee lifecycle tracking into one connected suite aimed at both small businesses and large enterprises. Because it inherits Odoo's modular, open-source architecture, the core Open HRMS modules are free to download and self-host, and organizations with in-house Odoo or technical expertise can run it without paying licensing fees. Cybrosys monetizes the project by offering managed hosting, implementation, customization, and ongoing support through tiered monthly plans: an Open HRMS Base plan at $49.90/month covering core HR functions like attendance, leave, employee history, custody tracking, appraisals, disciplinary tracking, resignation workflows, biometric device integration, background verification, and org charts for up to 50 users; a Base + Project Management plan at $59.99/month adding timesheets, project ratings, and branch transfers; a Base + Payroll plan at $79.99/month adding payroll processing, payslip reporting, shift management, gratuity settlement, loan management, salary advances, and region-specific compliance features such as Saudi GOSI contribution handling; and an All-in-One plan at $99.99/month combining project management, payroll, recruitment, multi-company support, HR dashboards, insurance management, and document management. Open HRMS's key differentiator versus dedicated commercial HR SaaS products like BambooHR, Gusto, or Zoho People is that it is fully open source and Odoo-native, meaning organizations already running Odoo for accounting, sales, or inventory can add HR functionality without integrating a separate third-party system, and technically capable teams can self-host and customize the codebase freely rather than being locked into a vendor's proprietary platform. Its target audience is small-to-mid-size businesses, particularly those in the Odoo ecosystem or in regions like the Middle East and South Asia where Cybrosys has a strong regional presence, who want HR functionality without a large enterprise software budget. Competing products include BambooHR, Zoho People, Gusto, and other Odoo HR alternatives; Open HRMS's edge is cost (free core software, moderate managed-support pricing) and deep ERP integration rather than being the most feature-rich standalone HR platform on the market.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8e6508f8-f264-449c-bf83-015dd51a8619';

