-- ── Open Policy Agent ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open Policy Agent (OPA) is a CNCF-graduated, open-source, general-purpose policy engine that lets developers write policy-as-code rules in the Rego language to enforce authorization and compliance across Kubernetes, microservices, and CI/CD pipelines.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$51-200 employees (Styra, founding sponsor)$q$, company_size),
  headquarters = COALESCE($q$Redwood City, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Open Policy Agent Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Open Policy Agent (OPA) review: the open-source, CNCF-graduated policy engine for Kubernetes and cloud-native authorization. Features, pricing, alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Open Policy Agent (OPA) is an open-source, general-purpose policy engine created in 2016 by Styra, a company founded that same year and headquartered in Redwood City, California, by co-founders including Tim Hinrichs (CTO) and Teemu Koponen. OPA was designed to unify policy enforcement, deciding what is and is not allowed, across heterogeneous technology stacks, rather than hard-coding authorization logic separately into every application, API gateway, CI/CD pipeline, or Kubernetes cluster. It uses a purpose-built declarative query language called Rego to express policy logic over structured JSON-like data, letting teams decouple policy decisions from application code and manage them as version-controlled, testable artifacts, an approach known as policy-as-code. OPA was donated to the Cloud Native Computing Foundation (CNCF), entering the CNCF Sandbox in 2018, reaching Incubation status in 2019, and achieving full Graduated status in 2021, making it the 15th CNCF project to graduate and the first focused entirely on authorization. It has been downloaded well over 100 million times and is used in production by major organizations including Netflix, Cloudflare, Pinterest, Intuit, and Capital One. The most common deployment pattern is OPA Gatekeeper, which uses OPA as an admission controller to enforce policy on Kubernetes resources before they are created or updated, but OPA is equally used for microservice API authorization, Terraform and infrastructure-as-code compliance checks (via tools like Conftest), and CI/CD pipeline gating. OPA itself is completely free and open source under an Apache 2.0-style license with no paid tier; monetization instead comes through Styra DAS (Declarative Authorization Service), a commercial management plane that adds centralized policy authoring, testing, impact analysis, and compliance reporting on top of open-source OPA deployments, aimed at enterprises running OPA at scale. In 2024, Apple hired several of OPA's core maintainers from Styra, including Koponen, Hinrichs, and Torin Sandall, while the open-source OPA project itself continues to be maintained under CNCF governance rather than by any single company, and the open-source community also continues to maintain Styra's other open-source products. OPA's primary differentiators are its cloud-native-first design, its CNCF-graduated maturity and vendor-neutral governance, and Rego's ability to express complex, hierarchical policy logic that simpler role-based access control (RBAC) systems cannot. Its closest alternatives include AWS Cedar, Kyverno (Kubernetes-native policy engine using YAML instead of Rego), Casbin, and cloud-provider-native IAM systems; OPA's edge is being usable consistently across any stack rather than being tied to one platform. Target users are platform engineering, DevOps, and security teams at organizations running Kubernetes and microservices architectures who need centralized, auditable authorization and compliance controls.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c1a8c047-6445-4dbd-ae16-412f8a2807f2';

