-- ── Open Source Routing Machine (OSRM) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OSRM is a free, open-source C++ routing engine that computes shortest paths and turn-by-turn directions on OpenStreetMap data, capable of routing across continent-sized road networks in milliseconds.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Volunteer-maintained open-source project; no formal company$q$, company_size),
  headquarters = COALESCE($q$Originated at Karlsruhe Institute of Technology, Karlsruhe, Germany; now community-maintained$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OSRM (Open Source Routing Machine) Review 2026: Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OSRM review: the free, open-source C++ routing engine for OpenStreetMap data. Features, performance, licensing, and top routing engine alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$The Open Source Routing Machine (OSRM) is a high-performance, open-source C++ routing engine for computing shortest paths and turn-by-turn directions on OpenStreetMap (OSM) data. It was first publicly released on 9 July 2010 by Dennis Luxen, who developed it as part of his research at the Karlsruhe Institute of Technology (KIT) in Germany; he later presented the underlying research alongside Christian Vetter at the ACM SIGSPATIAL GIS conference in 2011. OSRM is released under the permissive 2-clause BSD license, making it free to use, modify, and embed in both open-source and commercial products without royalty. Its core technical differentiator is speed: OSRM uses contraction hierarchies and other preprocessing techniques to answer shortest-path queries on continent-sized road networks in milliseconds, making it suitable for real-time navigation and routing applications rather than just offline batch route calculation. It supports multiple travel profiles out of the box, including driving, cycling, and walking, and its routing behavior can be customized through Lua-based profile scripts to model different vehicle types, road restrictions, or routing priorities. During the 2010s, OSRM powered Mapbox's turn-by-turn navigation and directions products, and Mapbox's Directions team contributed significantly to the codebase; however, in early 2018 Mapbox shifted its primary routing investment to the Valhalla engine (acquired via its hiring of the Mapzen team) and reduced active work on OSRM. Development slowed for a period after original creator Dennis Luxen stepped back from active leadership around 2015, but the project has continued under community-driven maintenance, with source code hosted on GitHub at Project-OSRM/osrm-backend, where the C++ backend repository alone has thousands of stars and continues to receive contributions. OSRM is not a company or commercial product: there is no vendor, no subscription tier, and no official hosted SaaS offering directly from the project, though it is used as an underlying engine by other companies and services that build routing products on top of it. This makes OSRM's competitive set primarily other open routing engines, such as Valhalla, GraphHopper, and OpenTripPlanner, as well as commercial routing APIs like Google Maps Directions, HERE, and Mapbox Directions (which no longer uses OSRM internally). OSRM's audience is developers, GIS engineers, logistics companies, and researchers who need to self-host a fast, customizable, license-free routing engine on OpenStreetMap data rather than pay per-request fees to a commercial mapping API, particularly for applications with high query volume where per-call API pricing would be costly at scale.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
