-- ── Open Web Analytics ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open Web Analytics (OWA) is a free, open-source, self-hosted web analytics platform created by Peter Adams that tracks visitors, pageviews, e-commerce transactions, and custom events while keeping full ownership of the data.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$Independent open-source project maintained by its creator and contributors$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (distributed open-source project)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Open Web Analytics Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Open Web Analytics review: the free, open-source, self-hosted alternative to Google Analytics. Features, WordPress plugin, licensing, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Open Web Analytics (OWA) is a free, open-source web analytics framework created by developer Peter Adams, with copyright notices in the codebase dating back to 2006. It is designed as a self-hosted alternative to Google Analytics: rather than sending visitor data to a third-party cloud service, organizations install OWA on their own PHP and MySQL server (a standard AMP/LAMP stack) and retain full ownership and control of their analytics data. The software is licensed under the GNU General Public License version 2 (GPL v2), and its source code is maintained publicly on GitHub under the Open-Web-Analytics organization, with the current stable release at version 1.8.1 as of September 2025 and over 2,700 GitHub stars. Functionally, OWA tracks website and application visitors, pageviews, e-commerce transactions, and custom, configurable actions or events, and it can monitor an effectively unlimited number of websites from a single server instance. Its feature set includes heatmap generation to visualize where visitors click and scroll, session replay-style visualization through a feature called DOMstream, geolocation tracking of visitors, and a dashboard-based reporting portal supporting multiple user accounts. Developers can integrate OWA directly using its PHP SDK for custom applications, or use the official WordPress plugin for turnkey tracking on WordPress sites; a REST API is also available for administration and programmatic data access, and the framework supports an extensible module system for adding custom tracking or reporting capabilities. Because OWA is entirely open source with no company behind it, there are no subscription tiers, no usage-based pricing, and no official hosted SaaS version; the project is sustained through community contributions and voluntary donations (a PayPal donation link is provided on the project's site) rather than commercial revenue. This makes OWA's closest comparison point Matomo (formerly Piwik), another open-source, self-hosted analytics platform, as well as privacy-focused hosted analytics tools like Plausible and Fathom, and of course Google Analytics itself as the dominant free commercial alternative. OWA's core differentiators are that it is completely free with no data caps or paid tiers, gives organizations full data ownership and privacy control since nothing leaves their own servers, and includes heatmap and session-visualization features not found in every open-source analytics tool. Its target users are website owners, developers, and organizations, particularly those with privacy, compliance, or data-sovereignty requirements, who want Google Analytics-style tracking without sending visitor data to a third party, and who have the technical capacity to self-host a PHP/MySQL application.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b8ecbeea-8621-4dc5-9c0a-606221d037c3';

