-- ── Open WebUI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open WebUI is a free, open-source, self-hosted web interface for interacting with local and remote large language models, supporting Ollama, OpenAI-compatible APIs, retrieval-augmented generation, and multi-user access control.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); Enterprise plan available at custom pricing$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Small core team (Open WebUI, Inc.) supported by 700+ open-source contributors$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (remote-first project)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and community-contributed interface translations$q$]::text[],
  seo_title = COALESCE($q$Open WebUI Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Open WebUI review: the free, open-source, self-hosted interface for local and remote LLMs. Features, RAG, Ollama support, pricing, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Open WebUI is a free, open-source, self-hosted web interface for interacting with large language models, created by developer Timothy Jaeryang Baek. It launched under the name Ollama WebUI, with its first public release (v0.1.102) on 25 September 2023 and its GitHub repository created on 6 October 2023, originally built as a user-friendly, ChatGPT-like frontend specifically for Ollama, the local LLM runtime. In January 2024 the project was renamed to Open WebUI after the Ollama team raised trademark-confusion concerns about the original name; the community voted on the new name via a GitHub discussion, and the rename coincided with the project expanding beyond Ollama to support additional backends including llama.cpp, LiteLLM, vLLM, and any OpenAI-compatible API, as well as providers like LMStudio, GroqCloud, Mistral, and OpenRouter. By March 2026 the project had grown to over 145,000 GitHub stars, more than 700 contributors, and over 355,000 community members, making it one of the most widely adopted open-source AI interface projects. Its feature set is extensive: local retrieval-augmented generation (RAG) backed by nine supported vector databases (including ChromaDB, PGVector, Qdrant, Milvus, and Elasticsearch) with hybrid BM25-plus-vector search and multiple document-extraction engines; granular role-based access control and user groups for multi-user deployments; an extensibility system called Filters, Actions, Pipes, Tools, and Skills, plus support for the Model Context Protocol (MCP) and OpenAPI-based tool integrations; integrated voice and video calling with multiple speech-to-text and text-to-speech providers; image generation through OpenAI DALL-E, Gemini, ComfyUI, and AUTOMATIC1111; and collaboration features including team channels, persistent memory, calendars, automations, and web search/browsing. The core software is free and open source, distributed under the Open WebUI License (a modified license requiring preservation of Open WebUI branding, with earlier contributions covered by their original licenses per a LICENSE_HISTORY file), and can be self-hosted via Docker or other deployment methods with no artificial feature caps. Open WebUI, Inc. was formally incorporated as a small startup, reportedly raising around $40,000 through early accelerator/incubator programs, and monetizes through an Enterprise plan offering custom theming and branding, SLA-backed support, and Long-Term Support (LTS) releases for organizations that need guarantees beyond the community-supported open-source edition. Its closest competitors are other local-LLM chat frontends such as LM Studio's UI, Jan, LibreChat, and Chatbot UI, as well as Ollama's own minimal default interface; Open WebUI's key differentiator is the breadth of its feature set (RAG, multi-user RBAC, voice/video, tool calling, image generation) combined with backend-agnostic support for virtually any LLM provider. Target users are developers, privacy-conscious individuals, and organizations that want a full-featured, ChatGPT-like interface running entirely on infrastructure they control, whether serving local models via Ollama or connecting to commercial APIs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '362996ad-6cda-41f1-8ec2-066aa387a46c';

